import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.dom.DOMSource;
import org.w3c.dom.*;
import java.util.HashMap;
import java.util.Map;

public class XMLParser {
    public static Map<String, String> parseConfig(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource is = new InputSource(new StringReader(xml));
        is.setSystemId("<unique-identifier>"); // Set a unique identifier to prevent XXE attacks
        Document doc = builder.parse(is);

        Map<String, String> config = new HashMap<>();
        NodeList nodeList = doc.getElementsByTagName("setting");
        for (int i = 0; i < nodeList.getLength(); i++) {
            Element element = (Element) nodeList.item(i);
            config.put(element.getAttribute("name"), element.getTextContent());
        }
        return config;
    }
}